css:
/* Import font */
@import url('https://static.zeoseven.com/zsft/3/main/result.css');

/* Base styles */
body {
    font-family: "undefined";
    font-weight: normal;
}

/* 消息块基础样式 */
#chat .mes .mes_block {
    background-color: rgba(255, 255, 255, 0.1) !important;
    backdrop-filter: blur(4px) !important;
    -webkit-backdrop-filter: blur(4px) !important;
    border: 1px solid rgba(255, 255, 255, 0.2);
    box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.15);
    border-radius: 15px;
    padding: clamp(10px, 2vw, 25px) clamp(15px, 3vw, 35px);
    width: fit-content;
}

/* Color variables */
* {
    --morandi-blue: #A6B5C5;
    --morandi-pink: #1B3F8B;
    --soft-gray: #F5F5F5;
    --black30a: rgb(166, 181, 197, 30%);
    --black50a: rgb(166, 181, 197, 50%);
    --black70a: rgb(166, 181, 197, 70%);
    --white20a: rgb(27, 63, 139, 20%);
    --white30a: rgb(27, 63, 139, 30%);
    --white50a: rgb(27, 63, 139, 50%);
    --grey30: rgb(245, 245, 245);
    --grey30a: rgb(245, 245, 245, 30%);
    --grey7070a: rgb(245, 245, 245, 70%);
}

/* Text input styling */
textarea, input[type="text"] {
    font-family: "undefined";
    color: #4A4A4A;
    background-color: var(--soft-gray);
    border: 2px solid var(--morandi-blue);
    border-radius: 10px;
}

textarea:focus, input[type="text"]:focus {
    border-color: var(--morandi-pink);
    box-shadow: 0 0 10px var(--morandi-blue);
}

/* Code block styling */
pre {
    background-color: #F8F8FF !important;
    border: 2px solid var(--morandi-blue) !important;
    color: #4A4A4A !important;
}

/* Quote text styling */
.mes_text q {
    color: #284B8C;
    text-shadow:
        0 0 1px rgba(255, 255, 255, 0.8),
        0 0 2px rgba(65, 105, 225, 0.4),
        0 0 3px rgba(27, 63, 139, 0.3);
    font-weight: 700;
    letter-spacing: 0.03em;
    text-rendering: optimizeLegibility;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    transform: translateZ(0);
    backface-visibility: hidden;
    font-feature-settings: "locl" 1, "halt" 1, "vert" 1;
    font-variant-east-asian: full-width;
    font-language-override: "ZHS";
    font-synthesis: none;
    paint-order: stroke fill;
}

/* Message icons and animations */
.chat-message, .mes {
    position: relative;
    overflow: visible !important;
}

@keyframes float {
    0% { transform: translateY(0px); }
    50% { transform: translateY(-5px); }
    100% { transform: translateY(0px); }
}

.chat-message.user::after,
.mes[is_user="true"]::after {
    content: "🌸";
    position: absolute;
    bottom: 5px;
    right: 5px;
    font-size: 20px;
    animation: float 3s infinite ease-in-out;
}

.chat-message.bot::after,
.mes:not([is_user="true"])::after {
    content: "🌼";
    position: absolute;
    bottom: 5px;
    left: 5px;
    font-size: 20px;
    animation: float 3s infinite ease-in-out;
}

/* Quote styling and glow effect */
blockquote {
    position: relative;
    padding: 15px 20px;
    margin: 10px 0;
    border-left: 4px solid var(--morandi-blue);
    background: rgba(166, 181, 197, 0.1);
    border-radius: 8px;
    font-style: italic;
    transition: all 0.3s ease;
}

@keyframes gentle-glow {
    0% { box-shadow: 0 0 5px var(--morandi-blue); }
    50% { box-shadow: 0 0 15px var(--morandi-blue); }
    100% { box-shadow: 0 0 5px var(--morandi-blue); }
}

blockquote:hover {
    animation: gentle-glow 2s infinite;
    background: rgba(166, 181, 197, 0.2);
}

blockquote::before {
    content: """;
    font-size: 2em;
    color: var(--morandi-blue);
    position: absolute;
    left: 5px;
    top: -5px;
    opacity: 0.5;
}

/* QR Bar styling */
#send_form:hover #qr--bar {
    height: 40px;
    transition: all 0.5s ease;
}

#qr--bar {
    height: 0.1px;
}

/* Message text adjustment */
#chat .mes_text {
    width: 100% !important;
    padding-right: 0 !important;
}
